func formatDuration(ms int64) string {
	if ms < 1000 {
		return Itoa(ms) + "ms"
	}
	sec := float64(ms) / 1000.0
	if sec < 60 {
		return fmt.Sprintf("%.1fs", sec)
	}
	min := int64(sec) / 60
	rem := int64(sec) % 60
	return Itoa(min) + "m " + Itoa(rem) + "s"
}

